<template>
    <div
        @mouseenter="onInternalEnter" 
        @mouseleave="onInternalLeave"
    >
        <div class="modal-title">
            <!-- Accessing title from the dictionary object -->
            <h2>{{ dataDictionary.title || 'Schedule Meeting' }}</h2>
        </div>

        <div class="appointment-content">
            <form @submit.prevent="handleSubmit">
                <!-- 1. Propose 2 dates -->
                <div class="section-label">Propose two meeting dates</div>
                <input type="datetime-local" v-model="form.date1" required />
                <input type="datetime-local" v-model="form.date2" required />


                <!-- 2. Meeting Type (Chips) -->
                <div class="section-label">Meeting Topic</div>
                <div class="chips-container">
                    <button 
                    class="chip"
                        v-for="type in meetingTypes" 
                        :key="type"
                        type="button"
                        :class="{ active: form.type === type }"
                        @click="form.type = type"
                    >
                        {{ type }}
                    </button>
                </div>

                <!-- 3. Details -->
                <textarea 
                    v-model="form.details" 
                    maxlength="300"
                    rows="4"
                    placeholder="What is this regarding?"
                ></textarea>

                <input type="email" v-model="form.email" placeholder="Provide an email we can respond to" required />

                <button type="submit">Submit Request</button>
            </form>
        </div>
    </div>
</template>

<script>
export default {
    name: "AppointmentChild",
    props: {
        // Change type to Object unless you are specifically passing a JS new Map()
        dataDictionary: {
            type: Object,
            required: true,
            default: () => ({ title: "Pi Teams" })
        }
    },
    data() {
        return {
            meetingTypes: this.dataDictionary.meetingTypes,
            form: {
                date1: '',
                date2: '',
                type: this.dataDictionary?.meetingTypes[0] | "",
                details: '',
                email: ''
            }
        }
    },
    methods: {
        handleSubmit() {
            console.log("Appointment Data:", this.form);
            // Emit to parent if needed
            this.$emit('submit-appointment', this.form);
        },
        onInternalEnter() {
            this.$emit('mouseenter-child', this.$options.name);
        },
        onInternalLeave() {
            this.$emit('mouseleave-child');
        }

    }
}
</script>
